// // This module implements a 16-bit shift register with asynchronous load and shift operations. The shift direction is controlled by a 'shift_left' signal. On the falling edge of the clock, load the input data if the 'load' signal is low, shift left if 'shift_left' is high, or shift right otherwise.
module shift_register(
    input clk,
    input load,
    input shift_right,
    input [15:0] d,
    output reg [15:0] q);always @(posedge clk) begin
    if (load)
        q <= d;
    else if (shift_right)
        q <= q >> 1;
    else
        q <= q << 1;
end
endmodule
